const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');

function createGrpcClient(protoPath, grpcHost, grpcPort) {
  const packageDefinition = protoLoader.loadSync(protoPath, {
    keepCase: true,
    longs: String,
    enums: String,
    defaults: true,
    oneofs: true
  });

  const grpcObject = grpc.loadPackageDefinition(packageDefinition);
  const client = new grpcObject.packageName.ServiceName(
    `${grpcHost}:${grpcPort}`,
    grpc.credentials.createInsecure()
  );

  return client;
}

function forwardHeadersToGrpc(req, grpcCall) {
  const metadata = new grpc.Metadata();
  
  // Forward standard headers
  if (req.headers['user-agent']) {
    metadata.add('user-agent', req.headers['user-agent']);
  }
  
  if (req.headers['x-forwarded-for']) {
    metadata.add('x-forwarded-for', req.headers['x-forwarded-for']);
  }
  
  // Forward custom headers
  Object.keys(req.headers).forEach(headerName => {
    if (headerName.startsWith('x-')) {
      metadata.add(headerName, req.headers[headerName]);
    }
  });
  
  // Forward authorization header if present
  if (req.headers.authorization) {
    metadata.add('authorization', req.headers.authorization);
  }
  
  return metadata;
}

async function handleHttpRequest(req, res, grpcClient, methodName, requestObject) {
  try {
    const metadata = forwardHeadersToGrpc(req, grpcClient);
    
    const response = await new Promise((resolve, reject) => {
      grpcClient[methodName](requestObject, metadata, (error, response) => {
        if (error) {
          reject(error);
        } else {
          resolve(response);
        }
      });
    });
    
    res.json(response);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
}

